        const bucket = this.data[key % this.size];
        for (const pair of bucket) {
            if (pair[0] === key) {
                pair[1] = value;
                return;
            }
        }
        bucket.push([key, value]);
    }

    get(key) {
        const bucket = this.data[key % this.size];
        for (const pair of bucket) {
            if (pair[0] === key) {
                return pair[1];
            }
        }
        return -1;
    }

    remove(key) {
        const bucket = this.data[key % this.size];
        const index = bucket.findIndex(pair => pair[0] === key);
        if (index !== -1) {
            bucket.splice(index, 1);
        }
    }
}
